import base64
import io
import threading
from playsound import playsound

# Вставьте свою строку base64 здесь
mp3_base64 = "data:audio/mpeg;base64,"

def play_sound():
    mp3_data = base64.b64decode(mp3_base64)
    # Создаем временный файл для проигрывания
    with open("temp.mp3", "wb") as f:
        f.write(mp3_data)
    playsound("temp.mp3")

# Запуск проигрывания в отдельном потоке
threading.Thread(target=play_sound, daemon=True).start()